def get_prompt(category: str, index: int = 0) -> str:
    """Get specific prompt from library"""
    if category in PROMPTS and index < len(PROMPTS[category]):
        return PROMPTS[category][index]
    return PROMPTS["general_photography"][0]  # Default

def list_categories() -> list:
    """List all available prompt categories"""
    return list(PROMPTS.keys())

def get_all_prompts_count() -> int:
    """Get total number of prompts"""
    return sum(len(v) for v in PROMPTS.values())

def get_category_prompts(category: str) -> list:
    """Get all prompts from a category"""
    return PROMPTS.get(category, [])
